import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    min_penalty = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        dist_to_customer = np.linalg.norm(cur_truck_pos - customer_pos)
        travel_time = dist_to_customer / truck_speed

        window_start, window_end = time_windows[i]

        if current_time + travel_time > window_end:
            penalty = float('inf')
        elif current_time + travel_time < window_start:
            penalty = window_start - (current_time + travel_time)
        else:
            penalty = 0

        if penalty < min_penalty:
            min_penalty = penalty
            best_node = i

    if best_node is None:
        return None

    return best_node
